sp_theme.css:
/* IBM Carbon Design System Theme for ServiceNow Service Portal */

/* Carbon Color Palette */
:root {
    /* IBM Carbon UI Colors */
    --carbon-ui-01: #ffffff;
    --carbon-ui-02: #f4f4f4;
    --carbon-ui-03: #e0e0e0;
    --carbon-ui-04: #8d8d8d;
    --carbon-ui-05: #161616;

    /* IBM Carbon Text Colors */
    --carbon-text-01: #161616;
    --carbon-text-02: #525252;
    --carbon-text-03: #a8a8a8;
    --carbon-text-04: #ffffff;
    --carbon-text-error: #da1e28;

    /* IBM Carbon Link Colors */
    --carbon-link-01: #0f62fe;
    --carbon-link-02: #0043ce;

    /* IBM Carbon Support Colors */
    --carbon-support-01: #da1e28; /* Error */
    --carbon-support-02: #24a148; /* Success */
    --carbon-support-03: #f1c21b; /* Warning */
    --carbon-support-04: #0043ce; /* Info */

    /* IBM Carbon Interactive Colors */
    --carbon-interactive-01: #0f62fe;
    --carbon-interactive-02: #393939;
    --carbon-interactive-03: #0f62fe;
    --carbon-interactive-04: #0f62fe;

    /* IBM Carbon Hover States */
    --carbon-hover-primary: #0353e9;
    --carbon-hover-primary-text: #0043ce;
    --carbon-hover-secondary: #4c4c4c;
    --carbon-hover-ui: #e5e5e5;
    --carbon-hover-selected-ui: #cacaca;
    --carbon-hover-danger: #ba1b23;

    /* IBM Carbon Active States */
    --carbon-active-primary: #002d9c;
    --carbon-active-secondary: #6f6f6f;
    --carbon-active-ui: #c6c6c6;
    --carbon-active-danger: #750e13;

    /* IBM Carbon Focus */
    --carbon-focus: #0f62fe;

    /* IBM Carbon Spacing */
    --carbon-spacing-01: 0.125rem;
    --carbon-spacing-02: 0.25rem;
    --carbon-spacing-03: 0.5rem;
    --carbon-spacing-04: 0.75rem;
    --carbon-spacing-05: 1rem;
    --carbon-spacing-06: 1.5rem;
    --carbon-spacing-07: 2rem;
    --carbon-spacing-08: 2.5rem;
    --carbon-spacing-09: 3rem;
    --carbon-spacing-10: 4rem;
    --carbon-spacing-11: 5rem;
    --carbon-spacing-12: 6rem;

    /* IBM Carbon Typography */
    --carbon-font-family: 'IBM Plex Sans', 'Helvetica Neue', Arial, sans-serif;
    --carbon-font-family-mono: 'IBM Plex Mono', 'Menlo', 'DejaVu Sans Mono', monospace;
}

/* Base Styles */
body {
    font-family: var(--carbon-font-family);
    color: var(--carbon-text-01);
    background-color: var(--carbon-ui-02);
    font-size: 14px;
    line-height: 1.5;
}

/* Typography */
h1, h2, h3, h4, h5, h6 {
    font-family: var(--carbon-font-family);
    color: var(--carbon-text-01);
    font-weight: 600;
}

h1 { font-size: 2.625rem; line-height: 1.19; }
h2 { font-size: 2rem; line-height: 1.25; }
h3 { font-size: 1.75rem; line-height: 1.29; }
h4 { font-size: 1.5rem; line-height: 1.33; }
h5 { font-size: 1.25rem; line-height: 1.4; }
h6 { font-size: 1rem; line-height: 1.5; }

/* Links */
a {
    color: var(--carbon-link-01);
    text-decoration: none;
    transition: color 0.11s cubic-bezier(0.2, 0, 0.38, 0.9);
}

a:hover {
    color: var(--carbon-hover-primary-text);
    text-decoration: underline;
}

a:active {
    color: var(--carbon-active-primary);
}

/* Buttons */
.btn, button {
    font-family: var(--carbon-font-family);
    font-size: 14px;
    font-weight: 400;
    line-height: 1.29;
    padding: var(--carbon-spacing-03) var(--carbon-spacing-05);
    border-radius: 0;
    border: none;
    cursor: pointer;
    transition: background-color 0.11s cubic-bezier(0.2, 0, 0.38, 0.9);
}

.btn-primary, .btn.btn-primary {
    background-color: var(--carbon-interactive-01);
    color: var(--carbon-text-04);
}

.btn-primary:hover {
    background-color: var(--carbon-hover-primary);
}

.btn-primary:active {
    background-color: var(--carbon-active-primary);
}

.btn-secondary, .btn.btn-secondary {
    background-color: var(--carbon-interactive-02);
    color: var(--carbon-text-04);
}

.btn-secondary:hover {
    background-color: var(--carbon-hover-secondary);
}

.btn-secondary:active {
    background-color: var(--carbon-active-secondary);
}

.btn-danger, .btn.btn-danger {
    background-color: var(--carbon-support-01);
    color: var(--carbon-text-04);
}

.btn-danger:hover {
    background-color: var(--carbon-hover-danger);
}

.btn-danger:active {
    background-color: var(--carbon-active-danger);
}

/* Forms */
.form-control, input[type="text"], input[type="email"], input[type="password"], 
input[type="number"], textarea, select {
    font-family: var(--carbon-font-family);
    font-size: 14px;
    padding: var(--carbon-spacing-03) var(--carbon-spacing-04);
    border: none;
    border-bottom: 1px solid var(--carbon-ui-04);
    background-color: var(--carbon-ui-01);
    color: var(--carbon-text-01);
    transition: border-color 0.11s cubic-bezier(0.2, 0, 0.38, 0.9);
}

.form-control:focus, input:focus, textarea:focus, select:focus {
    outline: 2px solid var(--carbon-focus);
    outline-offset: -2px;
    border-bottom-color: var(--carbon-focus);
}

.form-control:disabled, input:disabled, textarea:disabled, select:disabled {
    background-color: var(--carbon-ui-02);
    color: var(--carbon-text-03);
    cursor: not-allowed;
}

/* Cards */
.card, .panel {
    background-color: var(--carbon-ui-01);
    border: none;
    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
    margin-bottom: var(--carbon-spacing-05);
}

.card-header, .panel-heading {
    background-color: var(--carbon-ui-01);
    border-bottom: 1px solid var(--carbon-ui-03);
    padding: var(--carbon-spacing-05);
    font-weight: 600;
}

.card-body, .panel-body {
    padding: var(--carbon-spacing-05);
}

/* Navigation */
.navbar, .nav {
    background-color: var(--carbon-ui-05);
    border: none;
}

.navbar-nav > li > a, .nav > li > a {
    color: var(--carbon-text-04);
    padding: var(--carbon-spacing-04) var(--carbon-spacing-05);
    transition: background-color 0.11s cubic-bezier(0.2, 0, 0.38, 0.9);
}

.navbar-nav > li > a:hover, .nav > li > a:hover {
    background-color: var(--carbon-hover-secondary);
    color: var(--carbon-text-04);
}

.navbar-nav > li.active > a, .nav > li.active > a {
    background-color: var(--carbon-interactive-01);
    color: var(--carbon-text-04);
}

/* Tables */
.table {
    background-color: var(--carbon-ui-01);
    border-collapse: collapse;
}

.table thead th {
    background-color: var(--carbon-ui-03);
    color: var(--carbon-text-01);
    font-weight: 600;
    padding: var(--carbon-spacing-04);
    border-bottom: 1px solid var(--carbon-ui-04);
}

.table tbody td {
    padding: var(--carbon-spacing-04);
    border-bottom: 1px solid var(--carbon-ui-03);
}

.table tbody tr:hover {
    background-color: var(--carbon-hover-ui);
}

/* Alerts */
.alert {
    padding: var(--carbon-spacing-05);
    border-left: 3px solid;
    margin-bottom: var(--carbon-spacing-05);
}

.alert-success {
    background-color: #defbe6;
    border-left-color: var(--carbon-support-02);
    color: #0e6027;
}

.alert-info {
    background-color: #d0e2ff;
    border-left-color: var(--carbon-support-04);
    color: #001d6c;
}

.alert-warning {
    background-color: #fcf4d6;
    border-left-color: var(--carbon-support-03);
    color: #684e00;
}

.alert-danger {
    background-color: #fff1f1;
    border-left-color: var(--carbon-support-01);
    color: #750e13;
}

/* Modals */
.modal-content {
    background-color: var(--carbon-ui-01);
    border: none;
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);
}

.modal-header {
    background-color: var(--carbon-ui-01);
    border-bottom: 1px solid var(--carbon-ui-03);
    padding: var(--carbon-spacing-05);
}

.modal-body {
    padding: var(--carbon-spacing-05);
}

.modal-footer {
    background-color: var(--carbon-ui-01);
    border-top: 1px solid var(--carbon-ui-03);
    padding: var(--carbon-spacing-05);
}

/* Badges */
.badge, .label {
    background-color: var(--carbon-interactive-01);
    color: var(--carbon-text-04);
    padding: var(--carbon-spacing-01) var(--carbon-spacing-03);
    font-size: 12px;
    font-weight: 400;
    border-radius: 0;
}

/* Progress Bars */
.progress {
    background-color: var(--carbon-ui-03);
    height: 8px;
    border-radius: 0;
}

.progress-bar {
    background-color: var(--carbon-interactive-01);
}

/* Tooltips */
.tooltip {
    font-family: var(--carbon-font-family);
    font-size: 12px;
}

.tooltip-inner {
    background-color: var(--carbon-ui-05);
    color: var(--carbon-text-04);
    padding: var(--carbon-spacing-03) var(--carbon-spacing-04);
}

/* Dropdowns */
.dropdown-menu {
    background-color: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    box-shadow: 0 2px 6px rgba(0, 0, 0, 0.2);
    border-radius: 0;
}

.dropdown-menu > li > a {
    color: var(--carbon-text-01);
    padding: var(--carbon-spacing-03) var(--carbon-spacing-05);
}

.dropdown-menu > li > a:hover {
    background-color: var(--carbon-hover-ui);
    color: var(--carbon-text-01);
}

/* Pagination */
.pagination > li > a {
    background-color: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    color: var(--carbon-text-01);
    padding: var(--carbon-spacing-03) var(--carbon-spacing-04);
}

.pagination > li > a:hover {
    background-color: var(--carbon-hover-ui);
}

.pagination > .active > a {
    background-color: var(--carbon-interactive-01);
    border-color: var(--carbon-interactive-01);
    color: var(--carbon-text-04);
}

/* Service Portal Specific */
.navbar-inverse {
    background-color: var(--carbon-ui-05);
    border: none;
}

.navbar-inverse .navbar-brand {
    color: var(--carbon-text-04);
    font-weight: 600;
}

.navbar-inverse .navbar-nav > li > a {
    color: var(--carbon-text-04);
}

/* Widget Containers */
.widget-wrapper {
    margin-bottom: var(--carbon-spacing-05);
}

/* Focus Indicators */
*:focus {
    outline: 2px solid var(--carbon-focus);
    outline-offset: 2px;
}

button:focus, a:focus {
    outline-offset: -2px;
}

/* Scrollbars (Webkit) */
::-webkit-scrollbar {
    width: 8px;
    height: 8px;
}

::-webkit-scrollbar-track {
    background: var(--carbon-ui-02);
}

::-webkit-scrollbar-thumb {
    background: var(--carbon-ui-04);
}

::-webkit-scrollbar-thumb:hover {
    background: var(--carbon-text-02);
}

/* Utility Classes */
.carbon-spacing-01 { padding: var(--carbon-spacing-01); }
.carbon-spacing-02 { padding: var(--carbon-spacing-02); }
.carbon-spacing-03 { padding: var(--carbon-spacing-03); }
.carbon-spacing-04 { padding: var(--carbon-spacing-04); }
.carbon-spacing-05 { padding: var(--carbon-spacing-05); }
.carbon-spacing-06 { padding: var(--carbon-spacing-06); }
.carbon-spacing-07 { padding: var(--carbon-spacing-07); }

.carbon-bg-ui-01 { background-color: var(--carbon-ui-01); }
.carbon-bg-ui-02 { background-color: var(--carbon-ui-02); }
.carbon-bg-ui-03 { background-color: var(--carbon-ui-03); }
.carbon-bg-ui-05 { background-color: var(--carbon-ui-05); }

.carbon-text-01 { color: var(--carbon-text-01); }
.carbon-text-02 { color: var(--carbon-text-02); }
.carbon-text-03 { color: var(--carbon-text-03); }
.carbon-text-04 { color: var(--carbon-text-04); }

